fn solve(nums: Vec<i64>, k: i64) -> i64 {
    if nums.len() == 1 {
        return 0;
    }

    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    let mut min_remove = n as i64; // Maximum possible removals

    for i in 0..n {
        let left = i + 1;
        let mut right = n - 1;
        let mut best_j = n; // Default to removing all elements

        while left <= right {
            let mid = (left + right) / 2;
            if nums[mid] * k >= nums[i] {
                best_j = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        // The minimum number of elements to remove is n - best_j
        min_remove = std::cmp::min(min_remove, (n as i64 - best_j) as i64);
    }

    min_remove
}
